import React from "react";
import { motion } from "framer-motion";
import { Apple } from "lucide-react";

export function NavHeader() {
  return (
    <motion.header
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      className="relative z-50 w-full px-6 py-6 flex items-center justify-between"
    >
      <div className="flex items-center gap-2">
        <div className="p-2 bg-gradient-to-br from-primary to-secondary rounded-xl">
          <Apple className="w-6 h-6 text-white" />
        </div>
        <span className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-white/60">
          Foodies
        </span>
      </div>

      <nav className="hidden md:flex items-center gap-8">
        <a href="#how-it-works" className="text-sm font-medium text-white/60 hover:text-white transition-colors">How it Works</a>
        <a href="#impact" className="text-sm font-medium text-white/60 hover:text-white transition-colors">Impact</a>
        <a href="#community" className="text-sm font-medium text-white/60 hover:text-white transition-colors">Community</a>
      </nav>

      <div>
        <button className="px-5 py-2 text-sm font-semibold text-white/80 hover:text-white border border-white/10 rounded-full hover:bg-white/5 transition-all">
          Contact Support
        </button>
      </div>
    </motion.header>
  );
}
